  "appeal.faq_lang_q": { en: "Must the appeal letter be in English?", zh: "\u7533\u8bc9\u4fe1\u5fc5\u987b\u662f\u82f1\u6587\u7684\u5417？" },
  "appeal.faq_lang_a": { en: "Yes, recommended for US/EU markets. For Japan, you can attach a Japanese translation.", zh: "\u662f\u7684，\u5efa\u8bae\u7528\u4e8e\u7f8e\u56fd/\u6b27\u76df\u5e02\u573a。\u5bf9\u4e8e\u65e5\u672c，\u53ef\u4ee5\u9644\u4e0a\u65e5\u8bed\u7ffb\u8bd1。" },
